```python
class Contador:
    def __init__(self, inicio, fin):
        self.actual = inicio
        self.fin = fin

    def __iter__(self):
        return self  # el propio objeto es el iterador

    def __next__(self):
        if self.actual > self.fin:
            raise StopIteration  # señal de que terminó
        valor = self.actual
        self.actual += 1
        return valor

