import functools

def cache_simple(funcion):
    almacen = {}  # diccionario para guardar resultados

    @functools.wraps(funcion)
    def wrapper(*args):
        # Si los args ya están en almacen, devuelve el resultado guardado
        # Si no, calcula, guarda en almacen y devuelve
        pass

    return wrapper

@cache_simple
def fibonacci(n):
    """Calcula el n-ésimo número de Fibonacci."""
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

